A. 人事调动 长得非常像一道模拟，但是由于set会去重，map开的大小会达到 $N^2$ ，所以，我们可以使用multiset（其增删改查时间复杂度近似：O(log N)，即总时间复杂度为O(N log N)）。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst int N=100005;int n,q;int a[N],b[N];multiset&lt;int&gt; mp[N];multiset&lt;int&gt; ans;int main(){ freopen(&quot;work.in&quot;,&quot;r&quot;,stdin); freopen(&quot;work.out&quot;,&quot;w&quot;,stdout); ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; for(int i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]&gt;&gt;b[i]; mp[b[i]].insert(a[i]); } for(int i=1;i&lt;N;i++) { if(mp[i].empty()) { continue; } ans.insert(*(--mp[i].end())); } while(q--) { int c,d; cin&gt;&gt;c&gt;&gt;d; int id=b[c]; ans.erase(ans.find(*(--mp[id].end()))); mp[id].erase(mp[id].find(a[c])); if(!mp[id].empty()) { ans.insert(*(--mp[id].end())); } if(!mp[d].empty()) { ans.erase(ans.find(*(--mp[d].end()))); } mp[d].insert(a[c]); ans.insert(*(--mp[d].end())); b[c]=d; cout&lt;&lt;(*ans.begin())&lt;&lt;&quot;
&quot;; } return 0;} B. 失意 比较一眼的贪心，以区间左端点从小到大排序，用优先队列从小到大维护右端点，每次队列里有m个元素，就比较一次大小，超过m就把右端点最小的弹出去。每次比较记录此时的最大L和最小R（答案即R-L），最后再循环一边找到符合的m个区间。 注意：要特判答案为0的时候，任意输出m个区间即可 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst ll N=1000005;ll Num,n,m;struct node{ ll l,r,id; bool operator &lt;(node a) { return l&lt;a.l; }} a[N];priority_queue&lt;ll&gt; pq;bool f;ll ans,id1,id2;int main(){ freopen(&quot;failure.in&quot;,&quot;r&quot;,stdin); freopen(&quot;failure.out&quot;,&quot;w&quot;,stdout); ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;Num; cin&gt;&gt;n&gt;&gt;m; for(ll i=1;i&lt;=n;i++) { ll x,y; cin&gt;&gt;x&gt;&gt;y; a[i]={x,y,i}; } sort(a+1,a+n+1); for(ll i=1;i&lt;=n;i++) { pq.push(-a[i].r); while(pq.size()&gt;m) { pq.pop(); } if(pq.size()==m) { if(-pq.top()-a[i].l&gt;ans) { ans=-pq.top()-a[i].l; id1=a[i].l,id2=-pq.top(); } } } if(id1==0&amp;&amp;id2==0) { id1=1e9; } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; for(ll i=1;i&lt;=n;i++) { if(a[i].l&lt;=id1&amp;&amp;a[i].r&gt;=id2) { cout&lt;&lt;a[i].id&lt;&lt;&quot; &quot;; m--; } if(!m) { cout&lt;&lt;&quot;
&quot;; return 0; } } return 0;} C. 位于LIS概率 又是C&gt;&gt;&gt;&gt;&gt;&gt;D，扣C结果在还有3分钟结束的时候想到了正解，错失D大好90pts 70pts的做法就是没有线段树/树状数组优化的正解：求出整个数列的LIS长度mx；对于每个 $i∈{1…n}$ 求出以i结尾与以i开头的LIS长度 $x1$, $x2$ 和数量 $t1$, $t2$ ，如果其 $x1+x2-1=mx$，说明这是一种LIS，i在LIS中的情况数+= $t1	imes t2$，最后用快速幂求逆元即可。 用树状数组维护比较短（改成线段树只要改架构就行了）。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127128129130131132#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst ll N=1000005,mod=998244353;ll n,m;ll a[N],b[N];ll ans[N];struct node{ ll x,t; //长度，数量 } tr[N],pre[N],suf[N];node mx;ll qpow(ll a,ll b){ ll ret=1; while(b) { if(b&amp;1) { ret=ret*a%mod; } a=a*a%mod; b&gt;&gt;=1; } return ret;}void calc(node &amp;x,node y) //合并{ if(x.x==y.x) { x.t=(x.t+y.t)%mod; } else if(x.x&lt;y.x) { x=y; }}void update(ll x,node y){ while(x&lt;=m) { calc(tr[x],y); x+=x&amp;(-x); }}node query(ll x){ node ret={0,0}; while(x) { calc(ret,tr[x]); x-=x&amp;(-x); } return ret;}int main(){ freopen(&quot;lis.in&quot;,&quot;r&quot;,stdin); freopen(&quot;lis.out&quot;,&quot;w&quot;,stdout); ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(ll i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; b[i]=a[i]; } sort(b+1,b+n+1); m=unique(b+1,b+n+1)-b-1; for(ll i=1;i&lt;=n;i++) { a[i]=lower_bound(b+1,b+m+1,a[i])-b; } for(ll i=1;i&lt;=n;i++) { pre[i]=query(a[i]-1); pre[i].x++; calc(pre[i],{1,1}); update(a[i],pre[i]); calc(mx,pre[i]); } memset(tr,0,sizeof tr); for(ll i=n;i;i--) { a[i]=m-a[i]+1; suf[i]=query(a[i]-1); suf[i].x++; calc(suf[i],{1,1}); update(a[i],suf[i]); } for(ll i=1;i&lt;=n;i++) { if(pre[i].x+suf[i].x-1==mx.x) { ans[i]=pre[i].t*suf[i].t%mod; } } ll tt=qpow(mx.t,mod-2); for(ll i=1;i&lt;=n;i++) { cout&lt;&lt;ans[i]*tt%mod&lt;&lt;&quot; &quot;; } cout&lt;&lt;&quot;
&quot;; return 0;} D. 排队 暴力有90早知道不扣C了 补题之后感觉不是很复杂，不知道做法有没有假掉。 首先由题目我们明确了一些排序规则： 子节点在父节点前面 编号小的的子节点在编号大的子节点前面 因此，我们可以用dfs给每一个节点排序，并用优先队列维护空房间顺序。 对于操作1（来人）：弹出x次优先级最高房间，输出最后一个编号 对于操作2（走人）：我们发现对于被移动的人x，他只会影响他的祖先，倍增，直到到空房间，输出其上跳步数即可。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst int N=1e5+5;int n,t;vector&lt;int&gt; e[N];int par[N][25];int id[N];int tot; bool vis[N];void dfs(int x,int f){ par[x][0]=f; vector&lt;int&gt; son; son.clear(); for(auto y:e[x]) { if(y==f) { continue; } son.push_back(y); } sort(son.begin(),son.end()); for(auto y:son) { dfs(y,x); } id[x]=++tot;}struct node{ int v; bool operator &lt; (const node &amp;x) const { return id[v]&gt;id[x.v]; }};priority_queue&lt;node&gt;q;int main(){ freopen(&quot;queue.in&quot;,&quot;r&quot;,stdin); freopen(&quot;queue.out&quot;,&quot;w&quot;,stdout); ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;t; for(int i=1;i&lt;n;i++) { int a,b; cin&gt;&gt;a&gt;&gt;b; e[a].push_back(b); e[b].push_back(a); } dfs(1,0); for(int i=1;i&lt;=20;i++) { for(int j=1;j&lt;=n;j++) { par[j][i]=par[par[j][i-1]][i-1]; } } for(int i=1;i&lt;=n;i++) { q.push((node){i}); } while(t--) { int op,x; cin&gt;&gt;op&gt;&gt;x; if(op==1) { int v=0; for(int i=1;i&lt;=x;i++) { v=q.top().v; q.pop(); vis[v]=1; } cout&lt;&lt;v&lt;&lt;&quot;
&quot;; } else { int cnt=0; for(int i=20;i&gt;=0;i--) { if(vis[par[x][i]]) { x=par[x][i]; cnt+=(1&lt;&lt;i); } } vis[x]=0; q.push((node){x}); cout&lt;&lt;cnt&lt;&lt;&quot;
&quot;; } } return 0;} END…

GSS系列 - 题单 - 洛谷 又开天坑.mp4 做一下SPOJ的8道数据结构，但是什么时候能写完我也不知道qwq 关于SPOJ注册问题这个很多帖子都有讲，主要就是google的recaptcha用不了，把它更换成recaptcha.net的验证（虽然尝试跨越长城了，但是仍然用不了，不知道为啥） 解决方法就是安装 Gooreplacer(for Microsoft Edge) 下载完成后，点击橙色小刷子，在弹出的窗口中点击最上方的蓝色按钮“配置规则”。点击页面中表格上方的“新增”，在弹出的窗口内依次输入 www.google.com/recaptcha，“通配符”，recaptcha.net/recaptcha，点击“提交”。 正文GSS1思路这个比较简单，就是最基本的一个框架。 一个节点有4个部分：区间和sum、区间最大前缀和lmx，区间最大后缀和rmx，区间最大子段和mx 在算一个区间最大子段和时，会出现两种情况： 该区间最大子段和是左/右儿子的最大子段和 该区间最大子段和是左儿子的最大后缀和+右儿子的最大前缀和 在算一个区间的最大前缀/后缀和时，也会出现两种情况：（以前缀和为例） 该区间最大前缀和是左儿子的最大前缀和 该区间最大前缀和是左儿子的区间和加右儿子的最大前缀和 至此，我们就可以将线段树build起来了，有一个技巧注意一下，因为在接下来的题里也会用： ​ 重定义node结构体的”+“，或者写一个merge函数，表示node之间的加法，因为不仅有pushup会用到，query也会用。 然后关于query没有什么好讲的吧。就这样，看代码。 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst int N=50005;ll n,m;ll a[N];struct node{ ll sum,lmx,rmx,mx; node() { sum=lmx=rmx=mx=0; } } tr[N&lt;&lt;2];node merge(node x,node y){ node ans; ans.sum=x.sum+y.sum; ans.lmx=max(x.lmx,x.sum+y.lmx); ans.rmx=max(y.rmx,y.sum+x.rmx); ans.mx=max(max(x.mx,y.mx),x.rmx+y.lmx); return ans;}void pushup(ll p) { tr[p]=merge(tr[p&lt;&lt;1],tr[p&lt;&lt;1|1]);}void build(ll p,ll l,ll r) { if(l==r) { tr[p].lmx=tr[p].rmx=tr[p].mx=tr[p].sum=a[l]; return; } ll mid=(l+r)&gt;&gt;1; build(p&lt;&lt;1,l,mid); build(p&lt;&lt;1|1,mid+1,r); pushup(p);}node query(ll p,ll l,ll r,ll x,ll y) { if(x&lt;=l&amp;&amp;y&gt;=r) { return tr[p]; } ll mid=(l+r)&gt;&gt;1; node L,R; if(y&lt;=mid) { return query(p&lt;&lt;1,l,mid,x,y); } else if(x&gt;mid) { return query(p&lt;&lt;1|1,mid+1,r,x,y); } else { L=query(p&lt;&lt;1,l,mid,x,y); R=query(p&lt;&lt;1|1,mid+1,r,x,y); return merge(L,R); }}int main(){ ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(ll i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; } build(1,1,n); cin&gt;&gt;m; while(m--) { ll x,y; cin&gt;&gt;x&gt;&gt;y; cout&lt;&lt;query(1,1,n,x,y).mx&lt;&lt;&quot;
&quot;; } return 0;} GSS2思路没写，这个难，咕 代码1 GSS3思路本题在第一题的基础上加入了单点修改，没有任何攻击性（确信 update就很正常，把边界的点重新赋值，然后重新往上pushup一下就行了。 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127128129130131#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst int N=100005;int n,m;int a[N];struct node{ ll sum,lmx,rmx,mx; node() { sum=lmx=rmx=mx=0; } } tr[N&lt;&lt;2];node merge(node x,node y){ node ans; ans.sum=x.sum+y.sum; ans.lmx=max(x.lmx,x.sum+y.lmx); ans.rmx=max(y.rmx,y.sum+x.rmx); ans.mx=max(max(x.mx,y.mx),x.rmx+y.lmx); return ans;}void pushup(int p) { tr[p]=merge(tr[p&lt;&lt;1],tr[p&lt;&lt;1|1]);}void build(int p,int l,int r) { if(l==r) { tr[p].lmx=tr[p].rmx=tr[p].mx=tr[p].sum=a[l]; return; } int mid=(l+r)&gt;&gt;1; build(p&lt;&lt;1,l,mid); build(p&lt;&lt;1|1,mid+1,r); pushup(p);}void update(int p,int l,int r,int x,int v){ if(l==r) { tr[p].lmx=tr[p].rmx=tr[p].mx=tr[p].sum=v; return; } int mid=(l+r)&gt;&gt;1; if(x&lt;=mid) { update(p&lt;&lt;1,l,mid,x,v); } else { update(p&lt;&lt;1|1,mid+1,r,x,v); } pushup(p);}node query(ll p,ll l,ll r,ll x,ll y) { if(x&lt;=l&amp;&amp;y&gt;=r) { return tr[p]; } ll mid=(l+r)&gt;&gt;1; node L,R; if(y&lt;=mid) { return query(p&lt;&lt;1,l,mid,x,y); } else if(x&gt;mid) { return query(p&lt;&lt;1|1,mid+1,r,x,y); } else { L=query(p&lt;&lt;1,l,mid,x,y); R=query(p&lt;&lt;1|1,mid+1,r,x,y); return merge(L,R); }}int main(){ ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; } build(1,1,n); cin&gt;&gt;m; while(m--) { int op,x,y; cin&gt;&gt;op&gt;&gt;x&gt;&gt;y; if(op==0) { update(1,1,n,x,y); } else { cout&lt;&lt;query(1,1,n,x,y).mx&lt;&lt;&quot;
&quot;; } } return 0;} GSS4思路这题跟前面3问好像没啥关系，不知道为啥放这，但是总体架构仍然不变。 区间求和没有什么难度，但是在修改的时候如果每一个数用sqrt开一下方，常数会剧增，因此需要讨论一种特殊情况： ​ 如果这一个区间的最大值已经&lt;=1了，那么对其开方不会有用，可以跳过 所以在记区间和的基础上记一个区间最大值即可。 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127128129130131132133#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longmt19937 rnd(time(NULL));ll n,m;ll a[100005];struct node{ ll sum,mx; node() { sum=mx=0; }} tr[400005];node merge(node x,node y){ node ans; ans.sum=x.sum+y.sum; ans.mx=max(x.mx,y.mx); return ans;}void pushup(ll p){ tr[p]=merge(tr[p&lt;&lt;1],tr[p&lt;&lt;1|1]);}void build(ll p,ll l,ll r){ if(l==r) { tr[p].sum=tr[p].mx=a[l]; return ; } ll mid=l+r&gt;&gt;1; build(p&lt;&lt;1,l,mid); build(p&lt;&lt;1|1,mid+1,r); pushup(p);}void update(ll p,ll l,ll r,ll x,ll y){ if(l==r) { tr[p].sum=sqrt(tr[p].sum); tr[p].mx=sqrt(tr[p].mx); return ; } ll mid=(l+r)&gt;&gt;1; if(x&lt;=mid&amp;&amp;tr[p&lt;&lt;1].mx&gt;1) { update(p&lt;&lt;1,l,mid,x,y); } if(y&gt;mid&amp;&amp;tr[p&lt;&lt;1|1].mx&gt;1) { update(p&lt;&lt;1|1,mid+1,r,x,y); } pushup(p); }node query(ll p,ll l,ll r,ll x,ll y){ if(x&lt;=l&amp;&amp;y&gt;=r) { return tr[p]; } ll mid=(l+r)&gt;&gt;1; node L,R; if(x&lt;=mid) { L=query(p&lt;&lt;1,l,mid,x,y); } if(y&gt;mid) { R=query(p&lt;&lt;1|1,mid+1,r,x,y); } return merge(L,R);}int main(){ ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); for(ll cs=1;cin&gt;&gt;n;cs++) { for(ll i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; } build(1,1,n); cout&lt;&lt;&quot;Case #&quot;&lt;&lt;cs&lt;&lt;&quot;:
&quot;; cin&gt;&gt;m; while(m--) { ll op,x,y; cin&gt;&gt;op&gt;&gt;x&gt;&gt;y; if(x&gt;y) { swap(x,y); } if(op==0) { update(1,1,n,x,y); } else { cout&lt;&lt;query(1,1,n,x,y).sum&lt;&lt;&quot;
&quot;; } } cout&lt;&lt;&quot;
&quot;; } return 0;} GSS7思路在第三题的基础上加入树链剖分。 代码#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longconst int inf=0x3f3f3f3f;const int N=1e5+5;ll n,q;ll x[N];ll tot;ll head[N],to[N*2],nxt[N*2];ll cnt;ll dfn[N],id[N];ll sz[N],dep[N],hvy[N],top[N],par[N];struct node{ ll sum,lmx,rmx,mx,lz; node() { sum=lmx=rmx=mx=0; lz=inf; } } tr[N&lt;&lt;2];void add(ll u,ll v){ to[++tot]=v; nxt[tot]=head[u]; head[u]=tot;}void dfs1(ll u,ll f){ dep[u]=dep[f]+1; par[u]=f; sz[u]=1; for(ll i=head[u];i;i=nxt[i]) { ll v=to[i]; if(v==f) { continue; } dfs1(v,u); sz[u]+=sz[v]; if(sz[v]&gt;sz[hvy[u]]) { hvy[u]=v; } }}void dfs2(ll u,ll tp) { dfn[u]=++cnt; id[cnt]=u; top[u]=tp; if(!hvy[u]) { return; } dfs2(hvy[u],tp); for(ll i=head[u];i;i=nxt[i]) { ll v=to[i]; if(v==par[u]||v==hvy[u]) { continue; } dfs2(v,v); }}node merge(node x,node y){ node ans; ans.sum=x.sum+y.sum; ans.lmx=max(x.lmx,x.sum+y.lmx); ans.rmx=max(y.rmx,y.sum+x.rmx); ans.mx=max(max(x.mx,y.mx),x.rmx+y.lmx); ans.lz=inf; return ans;}void pushup(ll p){ tr[p]=merge(tr[p&lt;&lt;1],tr[p&lt;&lt;1|1]);}void build(ll p,ll l,ll r){ if(l==r) { tr[p].sum=x[id[l]]; tr[p].lmx=tr[p].rmx=tr[p].mx=max(tr[p].sum,0ll); tr[p].lz=inf; return; } ll mid=(l+r)&gt;&gt;1; build(p&lt;&lt;1,l,mid); build(p&lt;&lt;1|1,mid+1,r); pushup(p);}void pushdown(ll p,ll l,ll r){ if(tr[p].lz==inf) { return; } ll t=tr[p].lz; ll mid=(l+r)&gt;&gt;1; tr[p&lt;&lt;1].sum=(mid-l+1)*t; tr[p&lt;&lt;1].lmx=tr[p&lt;&lt;1].rmx=tr[p&lt;&lt;1].mx=max(tr[p&lt;&lt;1].sum,0ll); tr[p&lt;&lt;1].lz=t; tr[p&lt;&lt;1|1].sum=(r-mid)*t; tr[p&lt;&lt;1|1].lmx=tr[p&lt;&lt;1|1].rmx=tr[p&lt;&lt;1|1].mx=max(tr[p&lt;&lt;1|1].sum,0ll); tr[p&lt;&lt;1|1].lz=t; tr[p].lz=inf;}void update(ll x,ll y,ll p,ll l,ll r,ll k){ if(x&lt;=l&amp;&amp;r&lt;=y) { tr[p].sum=(r-l+1)*k; tr[p].lmx=tr[p].rmx=tr[p].mx=max(tr[p].sum,0ll); tr[p].lz=k; return; } pushdown(p,l,r); ll mid=(l+r)&gt;&gt;1; if(x&lt;=mid) { update(x,y,p&lt;&lt;1,l,mid,k); } if(mid&lt;y) { update(x,y,p&lt;&lt;1|1,mid+1,r,k); } pushup(p);}node query(ll x,ll y,ll p,ll l,ll r){ if(x&lt;=l&amp;&amp;r&lt;=y) { return tr[p]; } pushdown(p,l,r); ll mid=(l+r)&gt;&gt;1; node L,R; if(x&lt;=mid) { L=query(x,y,p&lt;&lt;1,l,mid); } if(mid&lt;y) { R=query(x,y,p&lt;&lt;1|1,mid+1,r); } return merge(L,R);}void update_chain(ll u,ll v,ll k){ ll fu=top[u],fv=top[v]; while(fu!=fv) { if(dep[fu]&lt;dep[fv]) { swap(u,v); swap(fu,fv); } update(dfn[fu],dfn[u],1,1,n,k); u=par[fu],fu=top[u]; } if(dep[u]&gt;dep[v]) { swap(u,v); } update(dfn[u],dfn[v],1,1,n,k);}node query_chain(ll u,ll v){ node L,R; ll fu=top[u],fv=top[v]; while(fu!=fv) { if(dep[fu]&lt;dep[fv]) { R=merge(query(dfn[fv],dfn[v],1,1,n),R); v=par[fv],fv=top[v]; } else { L=merge(query(dfn[fu],dfn[u],1,1,n),L); u=par[fu],fu=top[u]; } } if(dep[u]&gt;dep[v]) { L=merge(query(dfn[v],dfn[u],1,1,n),L); } else { R=merge(query(dfn[u],dfn[v],1,1,n),R); } swap(L.lmx,L.rmx); return merge(L,R);}int main(){ ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(ll i=1;i&lt;=n;i++) { cin&gt;&gt;x[i]; } for(ll i=1;i&lt;n;i++) { ll u,v; cin&gt;&gt;u&gt;&gt;v; add(u,v),add(v,u); } dfs1(1,0); dfs2(1,1); build(1,1,n); cin&gt;&gt;q; while(q--) { ll op,a,b,c; cin&gt;&gt;op&gt;&gt;a&gt;&gt;b; if(op==1) { cout&lt;&lt;query_chain(a,b).mx&lt;&lt;&quot;
&quot;; } else { cin&gt;&gt;c; update_chain(a,b,c); } } return 0;}

给出 $N (1 \leq N \leq 2000)$ 表示 $01$ 串的长度， $D(O \leq D &lt; N)$ 表示 $0$ 或 $1$ 的最大偏离距离，一个长度为 $N$ 的 $01$ 串和一个整数 $K(1 \leq K \leq10^8)$，请计算传输延迟发生后一共有多少种可能的 $01$ 串，以及其中第 $K$ 大的串是什么。 洛谷 思路首先这是一个分成两问的 DP 问题。通过原题，$01$ 串中两种位各自的数量不会发生变化，所以对于 DP 的状态，我们可以选用 $0$（或 $1$ ）的数量，即：$f[i][j]$ 表示 $i…n$ 为中使用 $j$ 个 $0$ 的方案数，这里倒着处理是为了求第二问。 另外，已知 $K(1 \leq K \leq10^8)$ ，如果 $f$ 数组的某一位超过 $10^8$ 那么它就会被取模，这会导致错误，因此我们开一个 $g$ 和 $f$ 的操作基本一致，但是如果某一位超过 $10^8$ ，就直接将其改为 $10^8+1$。 具体的转移还是比较直接的。 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longmt19937 rnd(time(NULL));const int mod=100000000;int n,d,k;string s; int f[2005][2005],g[2005][2005]; //f:Question 1; g:Question 2int cn0[2005],cn1[2005]; // 记录0和1的位置int main(){ ios::sync_with_stdio(false); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;d&gt;&gt;k&gt;&gt;s; s=&quot; &quot;+s; int l0=0,l1=0; for(int i=n;i&gt;0;i--) { if(s[i]=='0') { cn0[++l0]=i;; } else { cn1[++l1]=i;; } } f[n+1][0]=g[n+1][0]=1; for(int i=n+1;i&gt;1;i--) { for(int j=0;j&lt;=l0;j++) { if(f[i][j]) { if(j!=l0&amp;&amp;abs(i-1-cn0[j+1])&lt;=d) //当前位选择0 { if(!(j+l1!=n-i+1&amp;&amp;cn1[n-i+2-j]-i+2&gt;d)) { f[i-1][j+1]=(f[i-1][j+1]+f[i][j])%mod; g[i-1][j+1]=g[i-1][j+1]+g[i][j]; g[i-1][j+1]=min(g[i-1][j+1],mod+1); } } if(j+l1!=n-i+1&amp;&amp;abs(i-1-cn1[n-i+2-j])&lt;=d) //当前位选择1 { if(!(j!=l0&amp;&amp;cn0[j+1]-i+2&gt;d)) { f[i-1][j]=(f[i-1][j]+f[i][j])%mod; g[i-1][j]=g[i-1][j]+g[i][j]; g[i-1][j]=min(g[i-1][j],mod+1); } } }// ;cout&lt;&lt;f[i-1][j+1]&lt;&lt;&quot; &quot;&lt;&lt;f[i-1][j]&lt;&lt;&quot;
&quot;; } } cout&lt;&lt;f[1][l0]&lt;&lt;&quot;
&quot;; for(int i=1;i&lt;=n;i++) {// cout&lt;&lt;&quot;
&quot;&lt;&lt;g[i+1][l0-1]&lt;&lt;&quot; &quot;&lt;&lt;k&lt;&lt;&quot;
&quot;; if(g[i+1][l0-1]&gt;=k) // 如果当前位为0的方案多于k，就输出0，否则输出1 { cout&lt;&lt;0; l0--; } else { cout&lt;&lt;1; k-=g[i+1][l0-1]; } } return 0;}

