&quot;;; return 0;} D. Intersecting Intervals最水D题。 存一下所有开始时间和结束时间，然后按时间顺序排，注意由于区间左右皆开，所以开始要排在结束前面 然后如果遇到开始时间，ans+现有的未完区间，并且未完区间数+1，否则-1 请开long long 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longbool cmp(pair&lt;ll,ll&gt; x,pair&lt;ll,ll&gt; y){ if(x.first==y.first) { return x.second&lt;y.second; } return x.first&lt;y.first;}ll n,s,t;vector&lt;pair&lt;ll,ll&gt; &gt; v;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(ll i=0;i&lt;n;i++) { cin&gt;&gt;s&gt;&gt;t; v.push_back({s,0}); v.push_back({t,1}); } sort(v.begin(),v.end(),cmp); ll k=0,ans=0; for(ll i=0;i&lt;v.size();i++) { if(v[i].second==0) { ans+=k; k++; } else { k--; } } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} E. Guess the Sum为什么加了输入输出流解绑就会出现输入问题qwq，烦 参考jiangly大神的做法 (=_=) E又&gt;F了 非常匪夷所思地使用了最短路 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longint n,l,r; int v;int pre[300005];queue&lt;int&gt; q;int main(){// ios::sync_with_stdio(0);// cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;l&gt;&gt;r; r++; q.push(l); memset(pre,-1,sizeof pre); pre[l]=l; while(!q.empty()) { int x=q.front(); q.pop(); for(int i=1;i&lt;=(1&lt;&lt;n);i*=2) { for(auto y:{x-i,x+i}) { if(y&lt;0||y&gt;(1&lt;&lt;n)) { continue; } if(pre[y]==-1) { pre[y]=x; q.push(y); } } if(x&amp;i) { break; } } } ll ans=0; for(int i=r;i!=l;i=pre[i]) { int b=i,a=pre[i]; int t=1; if(a&gt;b) { swap(a,b); t=-t; } cout&lt;&lt;&quot;? &quot;&lt;&lt;__lg(b-a)&lt;&lt;&quot; &quot; &lt;&lt;a/(b-a)&lt;&lt;&quot;
