虽然这是一道幽默的绿题，但是博主打AtCoder发现自己竟然不会写最小生成树，遂有此文 洛谷 前言最小生成树首先来看一下Kruskal最小生成树算法 【模板】最小生成树 将所有的边存下来，并按长度排序 用并查集存储两个点是否在同一棵树上，是则跳过；不是则合并，并将答案加上边长 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longll n,m;ll cne; //生成树的边数 struct edge{ ll u,v,w;}e[2000005];ll par[100005];ll ans;bool f; //是否能够生成 ll find(ll x) //找根 { return (par[x]==x)?x:par[x]=find(par[x]); }bool cmp(edge a,edge b) //排序 { return a.w&lt;b.w;}void kruskal() //kruskal { for(ll i=1;i&lt;=m;i++) //循环每一条边 { ll u=find(e[i].u),v=find(e[i].v); if(u==v) //同根则跳过 { continue; } ans+=e[i].w; par[u]=v; //合并 cne++; if(cne+1==n) //如果边数为点数-1，就结束 { f=1; break; } }} int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;m; for(ll i=1;i&lt;=n;i++) //init { par[i]=i; } for(ll i=1;i&lt;=m;i++) { cin&gt;&gt;e[i].u&gt;&gt;e[i].v&gt;&gt;e[i].w; } sort(e+1,e+m+1,cmp); kruskal(); if(f==0) { cout&lt;&lt;&quot;orz
&quot;; return 0; } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} 思路本题在上边的Kruskal模板上进行一个减边的优化即可 每个星球用三维坐标 $(x_i,y_i,z_i)$ 来表示，而在两个星球 $A,B$ 之间建造隧道的价格为 $\min{|x_A-x_B|,|y_A-y_B|,|z_A-z_B|}$。 所以考虑三个点 $a, b, c$ $(a_x&lt;b_x&lt;c_x) $ 此时连接 $ab$, $bc$ 更优，意思是说，我们会连的边一定是相邻的 代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long longll n,m;ll cne;struct edge{ ll u,v,w;} e[2000005];struct node{ ll x,y,z,id;} a[2000005];ll par[100005];ll ans;ll find(ll x){ return (par[x]==x)?x:par[x]=find(par[x]); }bool cmp1(node a,node b) //以三种坐标分别排序找相邻{ return a.x&lt;b.x;}bool cmp2(node a,node b){ return a.y&lt;b.y;}bool cmp3(node a,node b){ return a.z&lt;b.z;}bool cmp(edge a,edge b){ return a.w&lt;b.w;}int dis(int x,int y){ return min(abs(a[x].x-a[y].x),min(abs(a[x].y-a[y].y),abs(a[x].z-a[y].z)));}void kruskal(){ for(ll i=1;i&lt;=m;i++) { ll u=find(e[i].u),v=find(e[i].v); if(u==v) { continue; } ans+=e[i].w; par[u]=v; cne++; if(cne+1==n) { break; } }} int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(ll i=1;i&lt;=n;i++) //init { par[i]=i; } for(ll i=1;i&lt;=n;i++) { cin&gt;&gt;a[i].x&gt;&gt;a[i].y&gt;&gt;a[i].z; a[i].id=i; } sort(a+1,a+n+1,cmp1); for(ll i=1;i&lt;n;i++) { e[++m].u=a[i].id; e[m].v=a[i+1].id; e[m].w=dis(i,i+1); } sort(a+1,a+n+1,cmp2); for(ll i=1;i&lt;n;i++) { e[++m].u=a[i].id; e[m].v=a[i+1].id; e[m].w=dis(i,i+1); } sort(a+1,a+n+1,cmp3); for(ll i=1;i&lt;n;i++) { e[++m].u=a[i].id; e[m].v=a[i+1].id; e[m].w=dis(i,i+1); } sort(e+1,e+m+1,cmp); kruskal(); cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;}

比赛链接 非常难绷地交了6发罚时。。。 题解A. AtCoder Line应该没什么好讲的 1234567891011121314151617181920212223242526272829#include&lt;bits/stdc++.h&gt;using namespace std;int n;int x,y,z;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;x&gt;&gt;y&gt;&gt;z; if(x&lt;y) { swap(x,y); } if(x&gt;=z&amp;&amp;y&lt;=z) { cout&lt;&lt;&quot;Yes
