&quot;; //如果k&gt;sqrt(n)，那么len&lt;sqrt(n) int sq=ceil(sqrt(n)); for(int i=sq;i&gt;0;i--) //直接枚举即可 { int cn=f(i); ans[cn]=max(ans[cn],i); } for(int i=n-1;i&gt;0;i--) { ans[i]=max(ans[i],ans[i+1]); } //如果k&lt;sqrt(n) for(int i=1;i&lt;=sq;i++) { int L=0,R=n/i; while(L&lt;R) { int mid=(L+R+1)/2; if(f(mid)&gt;=i) { L=mid; } else { R=mid-1; } } ans[i]=L; } for(int i=l;i&lt;=r;i++) { cout&lt;&lt;ans[i]&lt;&lt;&quot; &quot;; } cout&lt;&lt;&quot;
&quot;; } return 0;} Finished.

