&quot;; return 0;} E. Toward 0学校刚教完概率与期望，我却不会做，是__导致我这样的 看到1e18的数据范围直接被MLE劝退，愣是没有想到其实可以用map，是__导致我这样的！ 骰子只有1-6的点数，所以每次到的值都是可以写作 $⌊ rac{𝑛}{2^𝑖3^𝑗5^𝑘}⌋$ （因为 $⌊ rac{⌊ rac{n}{x}⌋}{y}⌋=⌊ rac{⌊ rac{n}{y}⌋}{x}⌋=⌊ rac{n}{xy}⌋$ ） 所以我们就可以聪明地使用map数组dp，得到以下递推公式： dp_i=min(x+dp_{⌊ rac{n}{a}⌋}, rac{6}{5}(y+i=\sum_{i=2}^{6}dp_{⌊ rac{n}{i}⌋}))123456789101112131415161718192021222324252627282930313233343536373839404142434445#include&lt;bits/stdc++.h&gt;using namespace std;long long n,a,x,y;map&lt;long long,double&gt; dp;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;a&gt;&gt;x&gt;&gt;y; dp[0]=0; for(long long i=1;i&lt;=n;i*=2) { for(long long j=1;i*j&lt;=n;j*=3) { for(long long k=1;i*j*k&lt;=n;k*=5) { dp[n/(i*j*k)]=0; //先新建可能取到的dp索引对应的dp数组的位置（因为使用map） } } } for(map&lt;long long,double&gt;::iterator i=dp.begin();i!=dp.end();i++) { if(!i-&gt;first) { continue; } double p=x+dp[i-&gt;first/a],q=6.0*y; //p是选择/a的期望，q是选择抛骰子的期望 for(int j=2;j&lt;=6;j++) { q+=dp[i-&gt;first/j]; } q/=5; i-&gt;second=min(p,q); //递推，最小代价 } cout&lt;&lt;fixed&lt;&lt;setprecision(6)&lt;&lt;dp[n]&lt;&lt;&quot;
&quot;; return 0;} F. Transpose非常经典的栈，试问Atcoder，为何E&gt;F。 其实感觉难度不是很大，不知道为什么是绿并F题，但话说我一直都很讨厌这种 (((()))(()) 的题QAQ 同样也是直接模拟，但是首先利用栈来记录这个字符串所有括号的位置和字母是否最终被反转 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788#include&lt;bits/stdc++.h&gt;using namespace std;string s;int p[500005]; //用于配对左括弧和右括弧的位置stack&lt;int&gt; st; //用于存储左括弧void output(int x,int y){ if(x&lt;=y) { for(int i=x;i&lt;=y;i++) { if(s[i]=='(') { if(p[i]!=i+1) //如果括号组内不为空 { output(p[i]-1,i+1); //整体翻转输出 } i=p[i]; //跳到下一组 } else { cout&lt;&lt;s[i]; } } } else { for(int i=x;i&gt;=y;i--) { if(s[i]==')') { if(p[i]!=i-1) { output(p[i]+1,i-1); //整体翻转输出 } i=p[i]; //跳到下一组 } else { cout&lt;&lt;s[i]; } } }}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;s; for(int i=0;i&lt;s.size();i++) { if(s[i]=='(') { st.push(i); } else if(s[i]==')') { p[st.top()]=i; p[i]=st.top(); st.pop(); } else { //如果这个字符在奇数个括号组里，就说明它会被大小写反转,偶数则会被反转回来 if(st.size()&amp;1) { if(s[i]&gt;='a'&amp;&amp;s[i]&lt;='z') { s[i]-='a'-'A'; } else { s[i]-='A'-'a'; } } } } output(0,s.size()-1); cout&lt;&lt;&quot;
&quot;; return 0;} G. Mediator一道被建议评橙的G题（现在是蓝），Atcoder怎么总能水暴力（？ 于是投喂一篇暴力（它甚至不需要吸氧就能过我真的 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667// Let us water a brute force ! #include&lt;bits/stdc++.h&gt;using namespace std;const long long mod=998244353;long long n,q;vector&lt;long long&gt; e[200005];bool t[200005];void geti(long long &amp;op,long long &amp;u,long long &amp;v,long long xl) //如题{ op=1+(((op*(1+xl))%mod)%2); u=1+(((u*(1+xl))%mod)%n); v=1+(((v*(1+xl))%mod)%n);}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; long long xl=0; while(q--) { memset(t,0,sizeof t); long long op,u,v; cin&gt;&gt;op&gt;&gt;u&gt;&gt;v; geti(op,u,v,xl); if(op==1) { e[v].push_back(u); e[u].push_back(v); //存边 continue; } for(long long i:e[u]) //遍历与u相邻的点 { t[i]=1; } bool flag=0; for(long long i:e[v]) { if(t[i]) //判断是否与v相邻 { cout&lt;&lt;i&lt;&lt;&quot;
&quot;; xl=i; flag=1; break; } } if(!flag) //否则输出0 { cout&lt;&lt;0&lt;&lt;&quot;
&quot;; xl=0; } } return 0;} 好吧下面是正解 使用启发式合并。如果两个点有一个共同的邻点，那么有三种可能： u是v的祖父 v是u的祖父 u和v是兄弟 所以依然使用带权并查集进行维护。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106#include&lt;bits/stdc++.h&gt;using namespace std;const long long mod=998244353;long long n,q;vector&lt;long long&gt; e[200005];int f[200005],par[200005],siz[200005];//分别为点i的父亲，点i的根，点i的深度void geti(long long &amp;op,long long &amp;u,long long &amp;v,long long xl){ op=1+(((op*(1+xl))%mod)%2); u=1+(((u*(1+xl))%mod)%n); v=1+(((v*(1+xl))%mod)%n);}void dfs(int x) //遍历并确定每个点的父亲节点{ for(auto i:e[x]) { if(i==f[x]) { continue; } f[i]=x; dfs(i); }}int query(int x,int y){ if(f[x]==f[y]&amp;&amp;f[x]) //如果两点为兄弟节点 { return f[x]; } if(f[f[x]]==y) //x的祖父为y { return f[x]; } if(f[f[y]]==x) //y的祖父为x { return f[y]; } return 0;}int find(int x) //找根{ return x==par[x]?x:par[x]=find(par[x]);}void merge(int x,int y) //合并{ int fx=find(x),fy=find(y); if(fx==fy) { return; } par[fy]=fx; siz[fx]+=siz[fy]; siz[fy]=0;}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; for(int i=1;i&lt;=n;i++) //初始化 { par[i]=i; siz[i]=1; } long long xl=0; while(q--) { long long op,u,v; cin&gt;&gt;op&gt;&gt;u&gt;&gt;v; geti(op,u,v,xl); if(op==1) { if(siz[find(u)]&lt;siz[find(v)]) { swap(u,v); } e[v].push_back(u); e[u].push_back(v); f[v]=u; merge(u,v); dfs(v); continue; } xl=query(u,v); cout&lt;&lt;xl&lt;&lt;&quot;
&quot;; } return 0;} wow写完啦！！！！！ 感谢观看呀
